class BankAccount:
    def __init__(self, owner):
        self.owner = owner
        self.balance = 0

    def deposit(self, amount):
        self.balance += amount
        print(f"Rs {amount} deposit hua. Balance: {self.balance}")

    def withdraw(self, amount):
        if amount > self.balance:
            print("Insufficient balance!")
        else:
            self.balance -= amount
            print(f"Rs {amount} nikala. Balance: {self.balance}")

    def get_balance(self):
        return self.balance

acc = BankAccount("Ali")
acc.deposit(1000)
acc.withdraw(500)
print(f"Final balance: {acc.get_balance()}")

